class Solution {
    public int[] validSequence(String word1, String word2) {
        int[] seq = new int[word2.length()];
        int diffCount = 0;
        for (int i = 0; i < word2.length(); i++) {
            if (word1.charAt(i) != word2.charAt(i)) {
                diffCount++;
                seq[i] = i;
            }
        }
        if (diffCount > 1) {
            return new int[0];
        }
        return seq;
    }
}
